"use client";

import { useState, useEffect } from "react";

interface EditorProps {
  section: string;
  data: any;
  onSave: (updated: any) => void;
}

export default function Editor({ section, data, onSave }: EditorProps) {
  const [content, setContent] = useState<any>(data);
  const [modalItem, setModalItem] = useState<any | null>(null);
  const [modalIndex, setModalIndex] = useState<number | null>(null);
  const [showConfirmIndex, setShowConfirmIndex] = useState<number | null>(null);

  useEffect(() => {
    setContent(data);
  }, [data]);

  const handleSave = () => {
    onSave(content);
    setModalItem(null);
    setModalIndex(null);
  };

  const handleEdit = (index: number) => {
    setModalItem({ ...content[index] });
    setModalIndex(index);
  };

  const handleDelete = (index: number) => {
    const updated = [...content];
    updated.splice(index, 1);
    setContent(updated);
    setShowConfirmIndex(null);
  };

  const handleAdd = () => {
    const keys = content[0] ? Object.keys(content[0]) : ["nombre"];
    const newItem = Object.fromEntries(keys.map(k => [k, ""]));
    setModalItem(newItem);
    setModalIndex(null);
  };

  const updateField = (key: string, value: string) => {
    setModalItem((prev: any) => ({ ...prev, [key]: value }));
  };

  const renderTable = () => (
    <div>
      <div className="flex justify-between items-center mb-4">
        <h3 className="text-lg font-semibold">{section.toUpperCase()}</h3>
        <button
          onClick={handleAdd}
          className="px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600"
        >
          + Agregar
        </button>
      </div>

      <table className="w-full text-sm border border-gray-300">
        <thead className="bg-gray-100">
          <tr>
            <th className="text-left px-3 py-2">Nombre</th>
            <th className="text-left px-3 py-2">Acciones</th>
          </tr>
        </thead>
        <tbody>
          {content.map((item: any, i: number) => (
            <tr key={i} className="border-t">
              <td className="px-3 py-2">{item.nombre || item.Producto}</td>
              <td className="px-3 py-2 space-x-2">
                <button
                  onClick={() => handleEdit(i)}
                  className="text-blue-600 hover:underline"
                >
                  Editar
                </button>
                <button
                  onClick={() => setShowConfirmIndex(i)}
                  className="text-red-600 hover:underline"
                >
                  Eliminar
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {showConfirmIndex !== null && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex justify-center items-center">
          <div className="bg-white p-6 rounded-xl shadow-xl">
            <p className="mb-4">¿Estás seguro de que deseas eliminar este ítem?</p>
            <div className="flex gap-4">
              <button
                onClick={() => handleDelete(showConfirmIndex)}
                className="px-4 py-2 bg-red-500 text-white rounded"
              >
                Sí, eliminar
              </button>
              <button
                onClick={() => setShowConfirmIndex(null)}
                className="px-4 py-2 bg-gray-300 rounded"
              >
                Cancelar
              </button>
            </div>
          </div>
        </div>
      )}

      {modalItem && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex justify-center items-center">
          <div className="bg-white max-w-xl w-full p-6 rounded-xl shadow-xl">
            <h4 className="text-lg font-semibold mb-4">{modalIndex !== null ? "Editar" : "Agregar"}</h4>
            {Object.entries(modalItem).map(([key, value]) => (
              <div key={key} className="mb-4">
                <label className="text-sm font-medium text-gray-700 block mb-1">{key}</label>
                <textarea
                  value={value}
                  onChange={(e) => updateField(key, e.target.value)}
                  className="w-full p-2 border border-gray-300 rounded"
                  rows={2}
                />
              </div>
            ))}
            <div className="flex justify-end gap-4 mt-4">
              <button
                onClick={() => {
                  const updated = [...content];
                  if (modalIndex !== null) updated[modalIndex] = modalItem;
                  else updated.push(modalItem);
                  setContent(updated);
                  setModalItem(null);
                  setModalIndex(null);
                }}
                className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
              >
                Guardar
              </button>
              <button
                onClick={() => {
                  setModalItem(null);
                  setModalIndex(null);
                }}
                className="px-4 py-2 bg-gray-300 rounded"
              >
                Cancelar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  return (
    <div>
      <h2 className="text-2xl font-bold text-blue-500 mb-6">Editar: {section}</h2>
      <form
        onSubmit={(e) => {
          e.preventDefault();
          handleSave();
        }}
        className="space-y-4"
      >
        {Array.isArray(content) && typeof content[0] === "object" ? renderTable() : null}
        {!Array.isArray(content) && typeof content === "object" && (
          <div>
            {Object.entries(content).map(([key, value]) => (
              <div key={key} className="mb-4">
                <label className="block text-sm font-semibold text-gray-700 mb-1">{key}</label>
                <textarea
                  value={value as string}
                  onChange={(e) => handleChange(key, e.target.value)}
                  className="w-full p-2 border border-gray-300 rounded"
                  rows={2}
                />
              </div>
            ))}
          </div>
        )}
        <button
          type="submit"
          className="bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700 transition"
        >
          Guardar Cambios
        </button>
      </form>
    </div>
  );
}
